class Solution:
    def findShortestSubArray(self, nums):
        from collections import Counter
        deg = max(Counter(nums).values())
        best = len(nums)
        n = len(nums)
        for i in range(n):
            c = Counter()
            for j in range(i, n):
                c[nums[j]] += 1
                if max(c.values()) == deg:
                    best = min(best, j - i + 1)
                    break
        return best

