class Solution:
    def findShortestSubArray(self, nums):
        first = {}
        count = {}
        last = {}
        for i, v in enumerate(nums):
            if v not in first:
                first[v] = i
            last[v] = i
            count[v] = count.get(v, 0) + 1
        deg = max(count.values())
        ans = len(nums)
        for v, c in count.items():
            if c == deg:
                ans = min(ans, last[v] - first[v] + 1)
        return ans

